/**
 * @name HTMLMacro content flow to output without sanitization
 * @description Trace HTML macro content to rendered output, checking if sanitization is bypassed
 * @kind path-problem
 * @problem.severity error
 * @id java/xwiki-htmlmacro-content-flow
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module HTMLMacroConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: macro content parameter (the HTML content passed to HTMLMacro)
    exists(MethodCall mc |
      mc.getMethod().hasName("getContent") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.xwiki.rendering.block", "AbstractMacroBlock") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: printRaw writes unescaped content to output
    exists(MethodCall mc |
      mc.getMethod().hasName("printRaw") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module HTMLMacroFlow = TaintTracking::Global<HTMLMacroConfig>;
import HTMLMacroFlow::PathGraph

from HTMLMacroFlow::PathNode source, HTMLMacroFlow::PathNode sink
where HTMLMacroFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTMLMacro content flows to printRaw() output - potential XSS if sanitization is bypassed"

/**
 * @name HTMLMacro restricted/clean mode bypass - taint flow to RawBlock output
 * @description When HTMLMacro clean=false or restricted mode, user content may reach raw HTML output
 * @kind path-problem
 * @problem.severity error
 * @id java/xwiki-htmlmacro-clean-false-xss
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module HTMLMacroRawConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: the content parameter in HTMLMacro.execute()
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasQualifiedName(
        "org.xwiki.rendering.internal.macro.html", "HTMLMacro") and
      p.getCallable().hasName("execute") and
      p.getType() instanceof TypeString and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: RawBlock constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName(
        "org.xwiki.rendering.block", "RawBlock") and
      sink.asExpr() = ce.getArgument(0)
    )
  }
}

module HTMLMacroRawFlow = TaintTracking::Global<HTMLMacroRawConfig>;
import HTMLMacroRawFlow::PathGraph

from HTMLMacroRawFlow::PathNode source, HTMLMacroRawFlow::PathNode sink
where HTMLMacroRawFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTML macro content (clean=false path) flows to RawBlock without sanitization - XSS risk"
